protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF9: default discriminator property renamed from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator", and direct SQL queries reference
        // c.Discriminator — keep the old name for backward compatibility.
        entity.HasDiscriminator<string>("Discriminator");

        // EF9: id values no longer include the discriminator prefix.
        // Existing documents have ids in "Product|123" format — preserve that format
        // so FindAsync and point-reads continue to work against existing data.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // EF9: HasIndex now throws for Cosmos entities. Cosmos DB indexing is managed
    // via the container's indexing policy (Azure Portal / Bicep / Terraform), not EF.
    // Removed: modelBuilder.Entity<Product>().HasIndex(p => p.Sku);
}

